What do you think about this?
```python
for period in 'day', 'weekday', 'hour', 'minute', 'second', 'microsecond':
    if hasattr(res, period):
        return 'day'
else:
    if hasattr(res, 'month'):
        return 'month'
    elif hasattr(res, 'year'):
        return 'year'
```
or
```python
day_periods = 'day', 'weekday', 'hour', 'minute', 'second', 'microsecond'
all_sufficient_periods = 'month', 'year'

for period in day_periods:
    if hasattr(res, period):
        return 'day'
else:
    for period in all_sufficient_periods:
        if hasattr(res, period):
            return period
```
or
```python
periods = OrderedDict([
    ('day', ['day', 'weekday', 'hour', 'minute', 'second', 'microsecond']),
    ('month', ['month']),
    ('year', ['year']),
])
for period, markers in periods.iteritems():
    for marker in markers:
        if hasattr(res, marked):
            return period
```

